import { createSlice } from '@reduxjs/toolkit';

const initialState = {
  orders: [],
  currentOrder: null,
  loading: false,
  error: null,
  success: false,
  paymentData: null,
  paymentLoading: false,
  paymentError: null,
  paymentVerified: false,
};

const orderSlice = createSlice({
  name: 'orders',
  initialState,
  reducers: {
    fetchOrdersRequest: (state) => {
      state.loading = true;
      state.error = null;
    },
    fetchOrdersSuccess: (state, action) => {
      state.loading = false;
      state.orders = action.payload;
    },
    fetchOrdersFailure: (state, action) => {
      state.loading = false;
      state.error = action.payload;
    },
    fetchOrderByNumberRequest: (state) => {
      state.loading = true;
      state.error = null;
    },
    fetchOrderByNumberSuccess: (state, action) => {
      state.loading = false;
      state.currentOrder = action.payload;
    },
    fetchOrderByNumberFailure: (state, action) => {
      state.loading = false;
      state.error = action.payload;
    },
    clearOrderState: (state) => {
      state.currentOrder = null;
      state.success = false;
      state.error = null;
      state.paymentData = null;
      state.paymentError = null;
      state.paymentVerified = false;
    },
    // Payment actions
    initializePaymentRequest: (state) => {
      state.paymentLoading = true;
      state.paymentError = null;
      state.paymentData = null;
    },
    initializePaymentSuccess: (state, action) => {
      state.paymentLoading = false;
      state.paymentData = action.payload;
    },
    initializePaymentFailure: (state, action) => {
      state.paymentLoading = false;
      state.paymentError = action.payload;
    },
    verifyPaymentRequest: (state) => {
      state.loading = true;
      state.error = null;
      state.paymentVerified = false;
    },
    verifyPaymentSuccess: (state, action) => {
      state.loading = false;
      state.currentOrder = action.payload.order;
      state.paymentVerified = true;
      state.success = true;
    },
    verifyPaymentFailure: (state, action) => {
      state.loading = false;
      state.error = action.payload;
      state.paymentVerified = false;
    },
    clearPaymentState: (state) => {
      state.paymentData = null;
      state.paymentError = null;
      state.paymentLoading = false;
      state.paymentVerified = false;
    },
  },
});

export const {
  fetchOrdersRequest,
  fetchOrdersSuccess,
  fetchOrdersFailure,
  fetchOrderByNumberRequest,
  fetchOrderByNumberSuccess,
  fetchOrderByNumberFailure,
  clearOrderState,
  initializePaymentRequest,
  initializePaymentSuccess,
  initializePaymentFailure,
  verifyPaymentRequest,
  verifyPaymentSuccess,
  verifyPaymentFailure,
  clearPaymentState,
} = orderSlice.actions;

export default orderSlice.reducer;
